import{_ as l,o as a,c as i,ag as r}from"./chunks/framework.ePeAWSvT.js";const s=JSON.parse('{"title":"Screen Policy: 검색","description":"","frontmatter":{},"headers":[],"relativePath":"검색_Screen_Policy_Final.md","filePath":"검색_Screen_Policy_Final.md"}'),e={name:"검색_Screen_Policy_Final.md"};function d(o,t,h,u,n,q){return a(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="screen-policy-검색" tabindex="-1">Screen Policy: 검색 <a class="header-anchor" href="#screen-policy-검색" aria-label="Permalink to &quot;Screen Policy: 검색&quot;">​</a></h1><hr><h2 id="■-screen-meta" tabindex="-1">■ Screen Meta <a class="header-anchor" href="#■-screen-meta" aria-label="Permalink to &quot;■ Screen Meta&quot;">​</a></h2><table tabindex="0"><thead><tr><th>항목</th><th>내용</th></tr></thead><tbody><tr><td>SCREEN_NAME</td><td>검색</td></tr><tr><td>화면 목적</td><td>제품명 또는 키워드를 입력하여 인쇄 제품/상품을 검색하고, 검색 결과를 필터링·정렬하여 조회</td></tr><tr><td>화면 URL</td><td>/search</td></tr></tbody></table><hr><h2 id="■-화면-구성-상태별" tabindex="-1">■ 화면 구성 (상태별) <a class="header-anchor" href="#■-화면-구성-상태별" aria-label="Permalink to &quot;■ 화면 구성 (상태별)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>상태</th><th>설명</th></tr></thead><tbody><tr><td>검색 초기 화면</td><td>검색 입력창 활성화, 최근 검색어 + 인기 검색어 + 추천 키워드 노출</td></tr><tr><td>검색결과 있을 때</td><td>검색 필터 + 정렬 + 결과 목록 노출</td></tr><tr><td>검색결과 없을 때</td><td>&quot;검색결과가 없습니다.&quot; 메시지 + 관리자 등록 추천 제품 영역 노출</td></tr></tbody></table><hr><h2 id="■-field-rule" tabindex="-1">■ Field Rule <a class="header-anchor" href="#■-field-rule" aria-label="Permalink to &quot;■ Field Rule&quot;">​</a></h2><h3 id="검색-입력창" tabindex="-1">[검색 입력창] <a class="header-anchor" href="#검색-입력창" aria-label="Permalink to &quot;[검색 입력창]&quot;">​</a></h3><ul><li>필수 여부: 선택</li><li>입력 규칙: 제품명 또는 키워드 텍스트 자유 입력 (특수문자 입력 차단)</li><li>placeholder: &quot;제품명 또는 키워드를 입력해주세요&quot;</li><li>길이 제한: 최대 30자</li><li>실행 조건: 엔터 입력 또는 검색 아이콘 클릭 시 검색 실행</li><li>미입력 검색 실행 시: 입력창 하단에 &quot;검색어를 입력해 주세요.&quot; 안내 메시지 표시</li><li>특수문자 입력 시: 입력 자체를 차단 (입력 불가 처리)</li></ul><hr><h3 id="최근-검색어" tabindex="-1">[최근 검색어] <a class="header-anchor" href="#최근-검색어" aria-label="Permalink to &quot;[최근 검색어]&quot;">​</a></h3><ul><li>노출 조건: 검색창 포커스 시 (초기 화면)</li><li>삭제 기능: &quot;모두 삭제&quot; 버튼으로 전체 삭제 가능</li><li>저장 방식: 로그인/비로그인 모두 브라우저 로컬 저장</li><li>최대 저장 개수: 5개 (초과 시 가장 오래된 항목부터 자동 삭제)</li></ul><hr><h3 id="인기-검색어" tabindex="-1">[인기 검색어] <a class="header-anchor" href="#인기-검색어" aria-label="Permalink to &quot;[인기 검색어]&quot;">​</a></h3><ul><li>노출 조건: 검색 초기 화면 (검색 전)</li><li>노출 예시: 최저가, 당일판, 대량인쇄, 디지털, 명함, 소봉투, 카탈로그</li><li>업데이트 기준: 현업 확인 필요</li><li>노출 개수: 5개</li><li>관리 방식: 내부 확인 필요</li></ul><hr><h3 id="추천-키워드" tabindex="-1">[추천 키워드] <a class="header-anchor" href="#추천-키워드" aria-label="Permalink to &quot;[추천 키워드]&quot;">​</a></h3><ul><li>노출 조건: 검색 초기 화면 (검색 전)</li><li>노출 예시: 명함, 디지털 전단지, 명함 카탈로그, 디지털 명함</li><li>관리 방식: 내부 확인 필요</li></ul><hr><h3 id="검색-필터-카테고리" tabindex="-1">[검색 필터 - 카테고리] <a class="header-anchor" href="#검색-필터-카테고리" aria-label="Permalink to &quot;[검색 필터 - 카테고리]&quot;">​</a></h3><ul><li>위치: 검색결과 화면 좌측 필터 영역</li><li>항목: 검색 결과에 포함된 카테고리만 동적 노출</li><li>&quot;전체&quot; 항목: 검색 결과 카테고리가 2개 이상일 때만 &quot;전체&quot; 항목 함께 노출</li><li>선택 방식: 단일 선택</li><li>초기값: &quot;전체&quot; 선택 상태 (카테고리가 1개인 경우 &quot;전체&quot; 미노출, 해당 카테고리만 표시)</li></ul><hr><h3 id="검색-필터-용지" tabindex="-1">[검색 필터 - 용지] <a class="header-anchor" href="#검색-필터-용지" aria-label="Permalink to &quot;[검색 필터 - 용지]&quot;">​</a></h3><ul><li>위치: 검색결과 화면 좌측 필터 영역</li><li>항목: 추후 데이터 수급 필요</li><li>노출 기준: 검색 결과에 포함된 제품에 해당하는 용지 종류만 동적 노출</li><li>선택 방식: 다중 선택 가능 (체크박스)</li><li>분류 구분: 스탠다드, 스페셜, 패키지</li><li>적용 시점: 선택 즉시 자동 반영</li></ul><hr><h3 id="검색-필터-오늘판" tabindex="-1">[검색 필터 - 오늘판] <a class="header-anchor" href="#검색-필터-오늘판" aria-label="Permalink to &quot;[검색 필터 - 오늘판]&quot;">​</a></h3><ul><li>위치: 검색결과 목록 우측 내용 영역 좌측 상단</li><li>선택 방식: 체크박스 (토글)</li><li>적용 시점: 선택 즉시 자동 반영</li><li>적용 시: &quot;오늘판 신청 가능&quot; 제품만 노출</li></ul><hr><h3 id="필터-초기화-버튼" tabindex="-1">[필터 초기화 버튼] <a class="header-anchor" href="#필터-초기화-버튼" aria-label="Permalink to &quot;[필터 초기화 버튼]&quot;">​</a></h3><ul><li>동작: 현재 선택된 모든 필터 초기화 → &quot;전체&quot; 상태로 복귀</li><li>노출 조건: 필터 선택 항목이 1개 이상일 때만 노출</li></ul><hr><h3 id="정렬-옵션" tabindex="-1">[정렬 옵션] <a class="header-anchor" href="#정렬-옵션" aria-label="Permalink to &quot;[정렬 옵션]&quot;">​</a></h3><ul><li>위치: 검색결과 목록 우측 내용 영역 좌측 상단</li><li>항목: 인기순, 낮은가격순, 높은가격순</li><li>초기값: 인기순</li><li>인기순 기준: 판매량순</li><li>선택 방식: 단일 선택, 클릭 즉시 반영</li></ul><hr><h2 id="■-검색결과-목록-제품-카드" tabindex="-1">■ 검색결과 목록 (제품 카드) <a class="header-anchor" href="#■-검색결과-목록-제품-카드" aria-label="Permalink to &quot;■ 검색결과 목록 (제품 카드)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>항목</th><th>내용</th></tr></thead><tbody><tr><td>제품 이미지</td><td>썸네일</td></tr><tr><td>제품명</td><td>텍스트</td></tr><tr><td>제품 설명</td><td>간략 설명 텍스트</td></tr><tr><td>키워드 태그</td><td>최대 5개, 태그당 최대 6자 (공백 포함)</td></tr><tr><td>오늘판 배지</td><td>썸네일 내 &quot;오늘판&quot; 배지 (해당 시 노출)</td></tr><tr><td>간편 접수 배지</td><td>썸네일 내 &quot;간편 접수&quot; 배지 (해당 시 노출)</td></tr><tr><td>최저 가격</td><td>₩X,XXX 형식</td></tr><tr><td>상세보기 버튼</td><td>제품 상세 페이지 이동</td></tr></tbody></table><h3 id="키워드-태그-규칙" tabindex="-1">[키워드 태그 규칙] <a class="header-anchor" href="#키워드-태그-규칙" aria-label="Permalink to &quot;[키워드 태그 규칙]&quot;">​</a></h3><ul><li>최대 개수: 5개</li><li>태그당 최대 글자수: 6자 (공백 포함)</li><li>초과 시 처리: 현업 확인 필요 (말줄임 처리 / 초과분 미노출)</li></ul><hr><h2 id="■-스크롤-정책" tabindex="-1">■ 스크롤 정책 <a class="header-anchor" href="#■-스크롤-정책" aria-label="Permalink to &quot;■ 스크롤 정책&quot;">​</a></h2><h3 id="스크롤-구조" tabindex="-1">[스크롤 구조] <a class="header-anchor" href="#스크롤-구조" aria-label="Permalink to &quot;[스크롤 구조]&quot;">​</a></h3><ul><li>좌측 필터 영역과 우측 검색결과 영역은 각각 독립적으로 스크롤</li></ul><h3 id="검색결과-목록" tabindex="-1">[검색결과 목록] <a class="header-anchor" href="#검색결과-목록" aria-label="Permalink to &quot;[검색결과 목록]&quot;">​</a></h3><ul><li>방식: 일반 스크롤 (무한 스크롤 미적용)</li><li>사유: 제품 수가 오픈마켓 대비 적으므로 전체 노출 후 스크롤 처리</li></ul><h3 id="좌측-네비게이션-더보기" tabindex="-1">[좌측 네비게이션 - 더보기] <a class="header-anchor" href="#좌측-네비게이션-더보기" aria-label="Permalink to &quot;[좌측 네비게이션 - 더보기]&quot;">​</a></h3><ul><li>노출 조건: 용지 또는 카테고리 항목이 10개 이상일 때 &quot;더보기&quot; 버튼 노출</li><li>동작: &quot;더보기&quot; 버튼 클릭 시 10건씩 추가 노출</li></ul><hr><h2 id="■-검색결과-없을-때" tabindex="-1">■ 검색결과 없을 때 <a class="header-anchor" href="#■-검색결과-없을-때" aria-label="Permalink to &quot;■ 검색결과 없을 때&quot;">​</a></h2><ul><li>메시지: &quot;검색결과가 없습니다.&quot;</li><li>하단 영역: &quot;지금 가장 인기있는 제품이에요&quot; 문구와 함께 추천 제품 목록 노출</li><li>추천 제품 관리: 관리자 수동 등록</li></ul><hr><h2 id="■-화면-결과" tabindex="-1">■ 화면 결과 <a class="header-anchor" href="#■-화면-결과" aria-label="Permalink to &quot;■ 화면 결과&quot;">​</a></h2><table tabindex="0"><thead><tr><th>시나리오</th><th>결과</th></tr></thead><tbody><tr><td>검색어 입력 후 결과 있음</td><td>검색 필터 + 정렬 + 제품 목록 노출</td></tr><tr><td>검색어 입력 후 결과 없음</td><td>&quot;검색결과가 없습니다.&quot; + 추천 제품 영역 노출</td></tr><tr><td>검색어 미입력 상태에서 검색 실행</td><td>입력창 하단에 &quot;검색어를 입력해 주세요.&quot; 안내 메시지 표시</td></tr><tr><td>최근 검색어 클릭</td><td>해당 키워드로 검색 실행</td></tr><tr><td>인기/추천 검색어 클릭</td><td>해당 키워드로 검색 실행</td></tr><tr><td>용지 필터 선택</td><td>선택 즉시 검색결과 자동 갱신</td></tr><tr><td>필터 초기화</td><td>전체 필터 해제 후 검색결과 갱신</td></tr><tr><td>정렬 변경</td><td>선택된 정렬 기준으로 즉시 재정렬</td></tr><tr><td>더보기 클릭</td><td>10건씩 추가 노출</td></tr><tr><td>제품 카드 - 상세보기</td><td>제품 상세 페이지 이동</td></tr></tbody></table><hr><h2 id="■-예외-상황" tabindex="-1">■ 예외 상황 <a class="header-anchor" href="#■-예외-상황" aria-label="Permalink to &quot;■ 예외 상황&quot;">​</a></h2><table tabindex="0"><thead><tr><th>상황</th><th>처리</th></tr></thead><tbody><tr><td>검색어 미입력 상태에서 검색 실행</td><td>입력창 하단 &quot;검색어를 입력해 주세요.&quot; 메시지 표시</td></tr><tr><td>특수문자 입력 시도</td><td>입력 차단 (입력 불가 처리)</td></tr><tr><td>네트워크 오류</td><td>&quot;일시적인 오류가 발생했습니다. 다시 시도해 주세요.&quot;</td></tr><tr><td>서버 오류</td><td>&quot;서비스 점검 중입니다. 잠시 후 다시 시도해 주세요.&quot;</td></tr></tbody></table><hr><h2 id="■-현업-확인-필요사항" tabindex="-1">■ 현업 확인 필요사항 <a class="header-anchor" href="#■-현업-확인-필요사항" aria-label="Permalink to &quot;■ 현업 확인 필요사항&quot;">​</a></h2><ul><li><strong>Q1. 검색 필터 용지 항목 데이터</strong><ul><li>필터에 노출할 용지 전체 목록 및 분류(스탠다드/스페셜/패키지) 기준 데이터 수급 필요</li></ul></li></ul><h2 id="■-내부-확인-필요사항" tabindex="-1">■ 내부 확인 필요사항 <a class="header-anchor" href="#■-내부-확인-필요사항" aria-label="Permalink to &quot;■ 내부 확인 필요사항&quot;">​</a></h2><ul><li><p><strong>Q1. 용지 상세보기 모달 콘텐츠 관리 방식</strong> ← 먼저 확인 필요</p><ul><li>모달에 노출되는 썸네일, 설명 등의 콘텐츠가 관리자 직접 등록 형태인지 확인 필요</li><li>관리자 등록 형태로 확인 시, 현업 확인 필요사항 Q1(용지 항목 데이터 수급)은 불필요하므로 함께 검토</li></ul></li><li><p><strong>Q2. 키워드 태그 운영 정책</strong></p><ul><li>제품당 등록 가능한 키워드 태그 개수 제한 여부 확인 필요</li><li>등록된 태그가 5개 초과 시 노출 방식 확인 필요 (랜덤 5개 노출 / 등록 순서대로 5개 노출 / 전체 노출 등)</li></ul></li><li><p><strong>Q3. 추천 키워드 관리 방식</strong></p><ul><li>운영자 수동 등록/관리 여부 확인 필요</li></ul></li><li><p><strong>Q4. 인기 검색어 관리 방식</strong></p><ul><li>운영자 수동 등록/관리 여부 확인 필요</li></ul></li></ul><hr><h2 id="■-필요-화면-목록" tabindex="-1">■ 필요 화면 목록 <a class="header-anchor" href="#■-필요-화면-목록" aria-label="Permalink to &quot;■ 필요 화면 목록&quot;">​</a></h2><table tabindex="0"><thead><tr><th>화면명</th><th>필요 사유</th></tr></thead><tbody><tr><td>검색어 자동완성</td><td>입력 중 연관 검색어 드롭다운 노출 여부 미확인</td></tr><tr><td>제품 상세</td><td>제품 카드 &quot;상세보기&quot; 클릭 후 이동 화면</td></tr></tbody></table>',65)])])}const b=l(e,[["render",d]]);export{s as __pageData,b as default};
